const MaintenanceSection: React.FC<MaintenanceSectionProps> = ({ systemConfig, onUpdateSystemConfig, onArchiveTasks, onDailyClosing, onWeeklyClosing, onGetDocCount, onPurgeOldTasks, onExportTasksJSON }) => {
