      if (!window.confirm("Spustiť dennú uzávierku? Všetky hotové úlohy budú presunuté do denného archívu.")) return;
      setIsClosing(true);
      const res = await onDailyClosing();
      alert(`Denná uzávierka úspešná. Presunutých ${res.count} úloh.`);
      setIsClosing(false);
