    if (!newIp.trim()) return;
    const currentList = systemConfig.allowedIPs || [];
    if (currentList.includes(newIp.trim())) {
      alert("Táto IP je už na zozname.");
      return;
    }
    onUpdateSystemConfig({ allowedIPs: [...currentList, newIp.trim()] });
