                  className="flex items-center justify-center gap-3 w-full py-4 mt-4 rounded-xl font-black uppercase text-[10px] tracking-[0.2em] transition-all bg-orange-500/10 text-orange-500 border border-orange-500/20 hover:bg-orange-500/20"
